def minimumDeleteSum(s1: str, s2: str) -> int:
    s1_char_count = {}
    s2_char_count = {}

    for char in s1:
        s1_char_count[char] = s1_char_count.get(char, 0) + 1
    for char in s2:
        s2_char_count[char] = s2_char_count.get(char, 0) + 1

    min_sum = float('inf')
    for char1 in s1:
        if char1 not in s2_char_count:
            continue
        for char2 in s2:
            if char2 not in s1_char_count:
                continue
            char1_count = s1_char_count[char1]
            char2_count = s2_char_count[char2]
            min_sum = min(min_sum, char1_count * char2_count)

    return min_sum

